-- Enrichment marathon batch: Simple Analytics, Simple Machines Forum, Simplecast, SimpleDMS, SimpleLogin, SimplePractice, Simplified, SimplyBook.me

-- ── Simple Analytics ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Simple Analytics is a privacy-first, cookieless web analytics platform from Amsterdam that gives site owners clear traffic insights without tracking, profiling, or storing personal data about visitors.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free plan available; paid plans from EUR 20 per month$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$2 employees (small, bootstrapped team)$q$, company_size),
  headquarters = COALESCE($q$Amsterdam, Netherlands$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Simple Analytics Review 2026: Pricing, Features and Privacy-First Analytics$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Simple Analytics delivers cookieless, GDPR-compliant web analytics. Compare pricing plans, features, pros and cons versus Google Analytics.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Simple Analytics is a privacy-focused, cookieless web analytics tool founded in 2018 by Dutch developer Adriaan van Rossum and headquartered in Amsterdam, Netherlands. The company was built as a direct response to concerns about Google Analytics' data collection practices and operates with a very small, bootstrapped team of around two people. Simple Analytics does not use cookies, does not track individual visitors across sessions, and does not store personal data, which lets customers run analytics without cookie consent banners. It is designed to comply with GDPR, PECR, and CCPA by default because it never collects personally identifiable information. The dashboard is a single page showing pageviews, visitors, referrers, top pages, screen sizes, and countries, aimed at people who want a fast, no-configuration alternative to Google Analytics. Simple Analytics offers a free forever plan with a small website limit and 30-day data history, alongside paid Self-Serve plans starting around EUR 20 per month that scale with pageview volume and unlock longer data retention, more users, and no dashboard badge requirement. An Enterprise tier adds raw data export, SSO, role-based access, Looker Studio integration, and support for security and procurement reviews including SOC 2 documentation. It is EU-hosted, making it a common choice for privacy-conscious founders, agencies, and SaaS companies operating under European data protection law. Competitors include Plausible Analytics, Fathom Analytics, and Matomo.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '721b3a38-d061-4bfd-94f0-6785a52684c9';

