-- ── Simple Machines Forum ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Simple Machines Forum (SMF) is a free, open-source PHP and MySQL bulletin-board application used to run online discussion communities and forums.$q$, short_description),
  pricing_model = COALESCE($q$free (open source)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2003, founded_year),
  company_size = COALESCE($q$Volunteer-run open-source project (Simple Machines LLC)$q$, company_size),
  headquarters = COALESCE($q$Arizona, United States (Simple Machines LLC registration)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Simple Machines Forum (SMF) Review 2026: Free Open-Source Forum Software$q$, seo_title),
  seo_meta_description = COALESCE($q$Simple Machines Forum is a free, open-source PHP forum platform. See its history, features, pros, cons, and how it compares to other bulletin-board software.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Simple Machines Forum, commonly known as SMF, is a free and open-source Internet forum and bulletin-board application written in PHP and backed by a MySQL database. It traces its lineage to YaBB (Yet Another Bulletin Board), an early open-source Perl forum script released in 2001, and later YaBB SE. A group of developers including Jeff Lewis and Matt Webb split off to rewrite the codebase from scratch, officially launching under the Simple Machines Forum name and brand in 2003. In 2006 the project was formally separated from its original commercial parent, Lewis Media, and transferred to a new entity, Simple Machines LLC, registered in Arizona, to reinforce its commitment to remaining free software without corporate control. SMF is distributed under its own license that keeps the core software free to download, install, and modify, while a large ecosystem of community-built themes and modifications extends its functionality. It is designed to be lightweight and easy to install even for site owners without deep programming experience, and it has historically been valued for strong security practices and moderation tooling. SMF competes with other self-hosted forum platforms such as phpBB, vBulletin, and Discourse, and remains popular among hobbyist communities, fan sites, and niche interest forums that want full control over their own hosting rather than relying on a hosted SaaS community platform.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd';

