-- ── Simplecast ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Simplecast is a podcast hosting, distribution, and analytics platform now owned by SiriusXM's AdsWizz, built for creators and publishers who need reliable distribution and detailed listener data.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$$15/month ($13.50/month billed annually)$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$Subsidiary of SiriusXM/AdsWizz (small dedicated team)$q$, company_size),
  headquarters = COALESCE($q$New York, New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Simplecast Review 2026: Podcast Hosting Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Compare Simplecast podcast hosting plans, analytics, and distribution features. See pricing, pros, cons, and FAQs before choosing a hosting platform.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Simplecast is a podcast hosting, distribution, and analytics platform founded in 2015 by Brad Smith, who grew it out of a product studio called Wayward Wild before becoming Simplecast's founder and CEO. The company is headquartered in New York and was acquired by SiriusXM in June 2020, where it now operates as the flagship podcast creator platform under AdsWizz, SiriusXM's ad-technology subsidiary. Simplecast lets podcasters upload episodes, automatically distribute them to Apple Podcasts, Spotify, and other major listening apps via RSS, and track detailed audience analytics including downloads, unique listeners, geographic location, device and app breakdowns, and on-site web player engagement through its Recast embeddable player. Pricing is tiered: a Basic plan starts at $15 per month (or $13.50 per month billed annually) with 20,000 downloads included, an Essential plan at $35 per month unlocks advanced location and technology analytics plus episode comparison reporting, and Professional and Enterprise tiers offer custom pricing with dynamic ad insertion through the AdsWizz Podcast Marketplace, white-labeled RSS feeds, and dedicated account management. All plans include a 14-day free trial. Simplecast is positioned for serious independent podcasters, media companies, and publishers who want professional-grade analytics and monetization tools rather than a bare-bones free hosting option, competing with platforms such as Libsyn, Buzzsprout, Transistor, and Acast.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'be61a68f-a190-43dc-9648-504807d5677a';

