-- ── SimpleDMS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$SimpleDMS is an open-source, tag-based document management system built for small and mid-size businesses, offering cloud, on-premises, and white-label deployment options.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$From CHF 5 per user per month (Pro plan)$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$SimpleDMS Review 2026: Open-Source Document Management Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$See what SimpleDMS offers small businesses: tag-based document organization, workspaces, versioning, and pricing plans for cloud, on-premises, and white-label use.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SimpleDMS is an open-source document management system positioned for small and mid-size businesses that want their files organized automatically instead of managing rigid folder trees. Rather than relying on manual filing, SimpleDMS uses a metadata- and tag-based system that suggests categorization as documents are uploaded, alongside workspaces that separate shared team documents from private files. Core capabilities include duplicate detection, document versioning, full-text search, and multiple document views, and the software can be installed as a desktop and mobile app across Windows, macOS, Linux, Android, and iOS, behaving like a native application once installed. SimpleDMS is available in three deployment models: a cloud-hosted SaaS offering, an on-premises install using source code released under a non-copyleft license, and a white-label SaaS option for partners who want to run their own multi-tenant instance. It integrates with tools such as Nextcloud, allowing files to be sent directly from Nextcloud Files into SimpleDMS. Pricing includes a Pro plan starting at roughly CHF 5 per user per month with 5 GB of cloud storage and unlimited workspaces, and an Unlimited plan at a flat rate of about CHF 395 per month with 500 GB of storage and unlimited users and workspaces. The product's primary market appears to be businesses in Austria, Germany, and Switzerland, though the self-hosted option is available worldwide. A free 30-day trial is offered. Independently verified founding year, headquarters, and company size were not available at the time of research.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b160eec3-7dec-4749-aa87-4cbf8e786590';

