-- ── SimpleLogin ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$SimpleLogin is an open-source email alias service that lets users shield their real email address behind unlimited disposable aliases, now owned by Proton AG.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free plan available; Premium from $2.99/month billed annually$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Part of Proton AG (500+ employees company-wide)$q$, company_size),
  headquarters = COALESCE($q$Paris, France (SimpleLogin origin); Proton AG headquartered in Geneva, Switzerland$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$SimpleLogin Review 2026: Email Alias Pricing, Features, and Proton Integration$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn how SimpleLogin's email alias service protects your inbox, how it integrates with Proton Pass, and what the free and premium plans include.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SimpleLogin is an open-source email alias and forwarding service founded in 2019 that lets users generate unlimited disposable email addresses which forward messages to a real inbox while hiding the user's actual email from websites and services. In April 2022, Proton AG, the company behind the encrypted email service ProtonMail, acquired SimpleLogin for an undisclosed sum; at the time of acquisition SimpleLogin had more than 100,000 users who had created over 2 million aliases. Since the acquisition, SimpleLogin has continued to operate as a standalone service while also being deeply integrated into Proton Pass, Proton's password manager, so Proton subscribers get alias creation built directly into their password vault. SimpleLogin's free plan includes 10 aliases, one mailbox, unlimited bandwidth, reply-from-alias functionality, browser extensions for Chrome, Firefox, and Safari, plus iOS and Android apps. The Premium plan costs $4 per month or $36 per year (previously priced lower, now aligned closer to $2.99 to $35.88 per year following integration with Proton Pass Plus) and adds unlimited aliases, unlimited custom domains, catch-all domain support, the ability to send new emails from an alias, multiple mailboxes, and PGP encryption. SimpleLogin is popular among privacy-conscious users who want to reduce spam, prevent data broker tracking, and quickly disable a compromised alias without changing their real email address, positioning it alongside alternatives like Apple Hide My Email, Firefox Relay, and DuckDuckGo Email Protection.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e645d12e-427d-4de8-a46d-9232f2a915d2';

