-- ── SimplePractice ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$SimplePractice is a cloud-based practice management and electronic health record platform built for therapists and other health and wellness professionals to manage scheduling, billing, and telehealth.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$$49/month (Starter plan)$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$501-1,000 employees$q$, company_size),
  headquarters = COALESCE($q$Santa Monica, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$SimplePractice Review 2026: EHR Pricing, Features, and Plans$q$, seo_title),
  seo_meta_description = COALESCE($q$Compare SimplePractice pricing plans, EHR features, and telehealth tools for therapists and health and wellness professionals before you sign up.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SimplePractice is a cloud-based practice management and electronic health record (EHR) platform built for health and wellness professionals such as therapists, counselors, psychologists, and other private-practice clinicians. It was founded in 2012 in Santa Monica, California, by Howard Spector while he was training to become a Marriage and Family Therapist, and the company remains headquartered in Santa Monica with roughly 500 to 1,000 employees. SimplePractice was acquired by EngageSmart in 2021 and continued operating as an independent product, and in January 2024 EngageSmart itself, including SimplePractice, was taken private through a roughly four billion dollar acquisition by Vista Equity Partners. The platform serves more than 225,000 practitioners and covers scheduling with online booking, HIPAA-compliant telehealth video sessions, client billing and insurance claim submission, customizable intake forms and progress notes, a client portal, and automated appointment reminders. Pricing starts at $49 per month for the Starter plan aimed at solo practitioners, scaling up through plans that add insurance billing tools, and a Plus plan for group practices priced at $99 per month base plus roughly $59 per month per additional clinician. New customers can start a paid plan within the first seven days of a free trial to receive a discount on their first three months. SimplePractice is widely used across behavioral health, and its main competitors include TherapyNotes, TheraNest, and Kareo.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c1f93663-fc76-4430-8326-61a4f8cb731a';

