INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$Cookieless tracking$q$, $q$Collects aggregate traffic data without cookies, device fingerprinting, or persistent identifiers, avoiding the need for a cookie consent banner on most sites.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$One-page dashboard$q$, $q$Shows pageviews, visitors, referrers, top pages, device types, and countries on a single, no-configuration screen.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$GDPR, PECR, and CCPA aligned$q$, $q$Built to comply with major privacy regulations by design, since no personal data is ever stored about individual visitors.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$Custom events and goals$q$, $q$Tracks conversions and custom interactions such as signups or purchases without relying on invasive event pipelines.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$Public and shared dashboards$q$, $q$Lets teams share live analytics with clients or stakeholders via a public link instead of granting account access.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$EU-hosted infrastructure$q$, $q$Data is processed and stored on EU servers, a common requirement for European businesses handling site analytics.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$API and data export$q$, $q$Paid plans include API access and raw data export for teams that want to integrate traffic data into other tools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$Proxy and ad-blocker resilience$q$, $q$Supports first-party proxy setups so the analytics script is served from a business's own domain, reducing ad-blocker interference.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$No cookie consent banner required on most implementations because no personal data is collected$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$Extremely fast, uncluttered dashboard that is easy for non-technical stakeholders to read$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$Transparent EU-based hosting and compliance posture aimed squarely at GDPR requirements$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$Free forever plan makes it easy to evaluate before committing to a paid tier$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$Small, founder-led team known for responsive support and product transparency$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$Less granular than Google Analytics or Mixpanel for deep behavioral or funnel analysis$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$Free plan is limited to a small number of websites and short data retention$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$Pricing rises with traffic volume, which can add up for high-traffic sites$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$No native mobile app analytics SDK comparable to larger platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$Smaller ecosystem of integrations and community resources than Google Analytics$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$Does Simple Analytics use cookies$q$, $q$No. Simple Analytics does not use cookies or any persistent identifiers, which is why most websites using it do not need to show a cookie consent banner under GDPR or PECR.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$Is Simple Analytics GDPR compliant$q$, $q$Yes. Simple Analytics is built to comply with GDPR, PECR, and CCPA by not collecting personal data or tracking individuals across sessions, and by hosting data within the EU.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$Does Simple Analytics have a free plan$q$, $q$Yes, Simple Analytics offers a free forever plan that covers a small number of websites with about 30 days of history, alongside paid Self-Serve and Enterprise plans.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$How much does Simple Analytics cost$q$, $q$Paid Self-Serve plans start at roughly EUR 20 per month and scale with monthly pageview volume. Enterprise pricing is custom and available on request.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$Who founded Simple Analytics$q$, $q$Simple Analytics was founded in 2018 by Dutch developer Adriaan van Rossum and is headquartered in Amsterdam, Netherlands.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$How is Simple Analytics different from Google Analytics$q$, $q$Simple Analytics avoids cookies and personal data collection entirely, offers a simpler single-page dashboard, and does not require a consent banner, whereas Google Analytics relies on cookies and detailed user-level tracking.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$Can I self-host Simple Analytics$q$, $q$Simple Analytics is offered as a hosted SaaS product with EU-based infrastructure; it is not distributed as self-hosted open-source software.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$What are common alternatives to Simple Analytics$q$, $q$Common alternatives include Plausible Analytics, Fathom Analytics, and Matomo, all of which also position themselves as privacy-friendly Google Analytics replacements.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$GDPR-friendly analytics for EU businesses$q$, $q$Companies operating under European data protection law use Simple Analytics to measure traffic without needing cookie consent banners or complex compliance reviews.$q$, $q$European SaaS companies and agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$Lightweight analytics for indie and side projects$q$, $q$Solo founders and small teams use the free plan to track pageviews and referrers without the overhead of setting up Google Analytics.$q$, $q$Indie developers and solo founders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$Client and stakeholder reporting$q$, $q$Agencies use public dashboards to share live traffic performance with clients without handing out login credentials.$q$, $q$Marketing and web agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$Free$q$, $q$$0$q$, $q$forever$q$, NULL, $q$["A handful of websites","About 30 days of data history","Basic one-page dashboard","No credit card required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$Self-Serve$q$, $q$From EUR 20/month$q$, $q$monthly or annual (2 months free annually)$q$, NULL, $q$["Scales with monthly pageviews","No cookies or consent banner required","EU-hosted and GDPR compliant","Custom events and goals","API access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$Enterprise$q$, $q$Custom$q$, $q$contact sales$q$, NULL, $q$["Raw data export","SSO and role-based access","Looker Studio integration","Priority support","Support for security and procurement reviews including SOC 2"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$overview$q$, $q$What Is Simple Analytics$q$, 2, ARRAY[$q$Simple Analytics is a web analytics platform built around a single premise: you should be able to understand your website traffic without tracking the people who visit it. Founded in 2018 in the Netherlands, the product was created after founder Adriaan van Rossum grew frustrated with the complexity, invasiveness, and consent-banner overhead of Google Analytics.$q$, $q$Instead of cookies, fingerprinting, or persistent identifiers, Simple Analytics aggregates anonymous, non-identifiable traffic data in real time. Because no personal data is collected, most sites running it do not need a cookie consent banner under GDPR or PECR, which is a major reason privacy-conscious founders and EU-based businesses adopt it.$q$, $q$The dashboard intentionally favors clarity over depth: pageviews, unique visitors, top referrers, top pages, device types, and countries are all visible on one screen with no funnel-building or event schema required to get started, though custom events and goals are supported for teams that need them.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Simple Analytics tracks pageviews and visitors without cookies or local storage, using a script that avoids anything that would classify as personal data collection under GDPR. This also means the tool is unaffected by browser cookie-blocking and ad-blocker behavior in many cases, since it does not rely on third-party tracking infrastructure.$q$, $q$Beyond basic traffic counts, the platform supports custom events, goal tracking, UTM campaign reporting, and a public dashboard option so teams can share live stats with stakeholders without giving out login access. An API and data export are available on paid and Enterprise plans for teams that want to pipe data into a warehouse or BI tool.$q$, $q$Simple Analytics also publishes its infrastructure and compliance posture openly, including EU-only hosting, and offers a proxy setup so analytics traffic is served from a business's own domain rather than a third-party one, improving both privacy optics and ad-blocker resilience.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('721b3a38-d061-4bfd-94f0-6785a52684c9', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Simple Analytics offers a genuinely free forever plan covering a handful of websites with about 30 days of history, aimed at hobby projects and evaluation.$q$, $q$The paid Self-Serve plan starts at roughly EUR 20 per month and scales with monthly pageview volume; pricing increases as traffic grows, and annual billing includes a discount equivalent to two free months.$q$, $q$An Enterprise plan with custom pricing adds raw data export, SSO, role-based access control, Looker Studio integration, priority support, and help with security or procurement reviews, targeting larger organizations with compliance requirements.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Threaded discussion boards$q$, $q$Organizes conversations into boards, topics, and threaded replies with support for sub-boards and categories.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Private messaging$q$, $q$Built-in member-to-member messaging system separate from public board posts.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Granular permissions and moderation$q$, $q$Role-based permission groups let administrators control who can post, moderate, or manage specific boards.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Theme and modification ecosystem$q$, $q$A large community library of themes and mods extends functionality without editing core files.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Self-hosted deployment$q$, $q$Runs on a site owner's own PHP and MySQL hosting, giving full control over data and customization.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Built-in search$q$, $q$Full-text search across posts, topics, and members to help users find existing discussions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Multi-language support$q$, $q$Community-maintained language packs allow forums to be run in languages beyond English.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Completely free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Long track record and mature codebase dating back to 2003$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Large community of themes and modifications for customization$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Full data ownership since the forum runs on the operator's own hosting$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Lightweight installation that does not require advanced server expertise$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Requires self-hosting, so the operator is responsible for security patches and uptime$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Interface feels dated compared to modern hosted community platforms like Discourse$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Smaller active development pace than some newer forum software$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$No built-in customer support since it is a community-driven open-source project$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Mobile-first responsiveness depends on the chosen theme rather than being standard$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Is Simple Machines Forum free$q$, $q$Yes. SMF is free, open-source forum software with no license fee. Costs come only from web hosting and any optional premium themes or modifications.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$What is SMF built with$q$, $q$SMF is written in PHP and uses a MySQL-compatible database, and it is designed to run on standard shared or dedicated web hosting.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$When was Simple Machines Forum founded$q$, $q$SMF launched under its current name and codebase in 2003, evolving from the earlier YaBB and YaBB SE open-source bulletin-board projects.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Who maintains Simple Machines Forum$q$, $q$SMF is maintained by Simple Machines LLC, an entity registered in Arizona, along with a community of open-source contributors.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$How does SMF compare to phpBB$q$, $q$Both are free, self-hosted, PHP-based forum platforms with long histories; the choice often comes down to preferred theme ecosystems, plugin availability, and personal familiarity with each admin interface.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Can I customize SMF with plugins$q$, $q$Yes, SMF supports a wide range of community-built themes and modifications that add features without modifying the core software.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Does SMF support multiple languages$q$, $q$Yes, community-maintained language packs let forum administrators run SMF in languages other than English.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Is SMF a good choice for a new online community in 2026$q$, $q$SMF remains a solid option for operators who want full control over self-hosted data and are comfortable managing their own server, though newer hosted platforms may offer a more modern out-of-the-box experience.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Hobbyist and fan community forums$q$, $q$Enthusiast communities use SMF to run dedicated discussion boards around shared interests without paying ongoing SaaS subscription fees.$q$, $q$Hobbyist community operators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Support and knowledge-sharing forums$q$, $q$Businesses and open-source projects self-host SMF as a searchable archive for user support questions and answers.$q$, $q$Small businesses and open-source projects$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Regional or niche interest communities$q$, $q$Operators who need full data ownership and custom moderation policy choose SMF over hosted community platforms.$q$, $q$Independent community administrators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$Open Source (Self-Hosted)$q$, $q$$0$q$, $q$free forever$q$, NULL, $q$["Full SMF software download","Threaded boards and private messaging","Community themes and modifications","Self-managed hosting required"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$overview$q$, $q$What Is Simple Machines Forum$q$, 2, ARRAY[$q$Simple Machines Forum (SMF) is open-source forum software that site owners install on their own server to run a discussion board or online community. It is written in PHP and uses MySQL for data storage, and it has been actively developed and maintained since 2003.$q$, $q$SMF's roots go back to YaBB, one of the earliest open-source Perl-based bulletin boards, released in 2001. A group of contributors later rewrote the software from the ground up in PHP and rebranded it as Simple Machines Forum, aiming for a codebase that was easier to run and extend than the tools available at the time.$q$, $q$In 2006 the project split from its original commercial sponsor and moved under Simple Machines LLC, a company registered in Arizona, to keep the software free and independent of outside corporate control. SMF remains free to download and self-host today.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$SMF provides the core building blocks expected of forum software: threaded discussion boards, private messaging, user profiles, a permissions and moderation system, and search across posts and topics.$q$, $q$The platform supports a large library of community-created themes and modifications (often called mods) that can add features like social login, gamification, calendars, and custom profile fields without altering the core codebase.$q$, $q$Because SMF is self-hosted, administrators have full control over data, moderation policy, and server-level customization, which appeals to communities that do not want to depend on a third-party SaaS forum host.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$SMF itself is free and open source; there is no license fee to download, install, or run the software.$q$, $q$The real cost of running SMF comes from web hosting, a MySQL-compatible database, and any premium third-party themes or modifications a community chooses to install.$q$, $q$Because there is no vendor subscription, ongoing costs depend entirely on hosting choices, making SMF attractive to budget-conscious community operators willing to manage their own server.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3ab9e86a-5b4d-418a-bbf7-fa7413ce25bd', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Automated multi-platform distribution$q$, $q$Publishes episodes to Apple Podcasts, Spotify, and other directories automatically through a single managed RSS feed.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Customizable show website$q$, $q$Provides a hosted, customizable podcast website with support for a custom domain.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Detailed listener analytics$q$, $q$Tracks downloads, unique listeners, geography, device and app technology, and episode-to-episode comparisons.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Recast embeddable web player$q$, $q$Lets podcasters embed shareable audio players with episode clips directly on websites and social posts.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Dynamic ad insertion$q$, $q$Professional and Enterprise plans support monetization through the AdsWizz Podcast Marketplace with dynamic ad insertion.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Team collaboration seats$q$, $q$Plans include multiple team member seats for producers, editors, and hosts to collaborate on show management.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$API and white-label options$q$, $q$Enterprise customers get API integration and white-labeled RSS feeds for custom publishing workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Secure HTTPS hosting$q$, $q$All shows are served over secure HTTPS with a protected RSS feed by default.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Strong, detailed analytics compared to many entry-level podcast hosts$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Backing from SiriusXM and AdsWizz brings monetization opportunities for larger shows$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Clean, easy-to-use publishing interface and customizable show website$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$14-day free trial available on all plans with no credit card required$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Recast web player makes it easy to share episode clips for marketing$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$No permanent free plan, unlike some competitors aimed at hobbyist podcasters$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Advanced analytics such as location and technology data are locked behind the Essential tier and above$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Professional and Enterprise pricing is not published and requires contacting sales$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Download-based pricing means costs can rise as a show's audience grows$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Fewer built-in editing tools compared to platforms that bundle recording and editing$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$How much does Simplecast cost$q$, $q$Simplecast's Basic plan starts at $15 per month ($13.50 billed annually), with an Essential plan at $35 per month, and custom-priced Professional and Enterprise tiers for larger publishers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Does Simplecast offer a free trial$q$, $q$Yes, all Simplecast plans include a 14-day free trial with no credit card required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Who owns Simplecast$q$, $q$Simplecast was acquired by SiriusXM in 2020 and now operates as AdsWizz's flagship podcast creator platform.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Does Simplecast support podcast monetization$q$, $q$Yes, Professional and Enterprise plans support dynamic ad insertion and campaign management through the AdsWizz Podcast Marketplace.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$What analytics does Simplecast provide$q$, $q$Simplecast tracks downloads, unique listeners, geographic location, device and app technology data, and web player engagement, with more advanced reporting on higher-tier plans.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Can I use a custom domain with Simplecast$q$, $q$Yes, Simplecast's customizable show website supports a custom domain on all plans.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Who founded Simplecast$q$, $q$Simplecast was founded in 2015 by Brad Smith, who later became Head of Podcast Products at SiriusXM.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Is Simplecast good for beginners$q$, $q$Simplecast is usable by beginners but is generally positioned toward serious podcasters and publishers who want professional analytics rather than the cheapest possible entry-level hosting.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Independent podcasters scaling an audience$q$, $q$Creators use Simplecast's analytics to understand listener geography and platform usage as their show grows beyond a hobby project.$q$, $q$Independent podcast hosts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Media companies and publishers$q$, $q$Publishers with multiple shows use Simplecast's Professional and Enterprise tools for monetization, white-labeling, and dedicated support.$q$, $q$Podcast networks and media publishers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Branded and marketing podcasts$q$, $q$Companies running a branded podcast use the customizable show website and Recast player to promote episodes on their own marketing channels.$q$, $q$Marketing and brand teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Basic$q$, $q$$15/month ($13.50/month annual)$q$, $q$monthly or annual$q$, NULL, $q$["2 team seats","Unlimited storage and uploads","Distribution to all major platforms","Basic analytics","Customizable show website with custom domain","20,000 downloads included per month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Essential$q$, $q$$35/month ($31.50/month annual)$q$, $q$monthly or annual$q$, NULL, $q$["4 team seats","Location analytics by country and region","Unique listener reports","Web player and technology analytics","Episode comparison reporting","50,000 downloads included per month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Professional$q$, $q$Custom$q$, $q$contact sales$q$, NULL, $q$["All Basic and Essential features","Dynamic ad insertion and campaign management","Comprehensive reporting suite","Secondary ad-free feeds","Priority customer support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$Enterprise$q$, $q$Custom$q$, $q$contact sales$q$, NULL, $q$["All Professional features","API integration","White-labeled RSS feeds","High bitrate audio","Dedicated success manager"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$overview$q$, $q$What Is Simplecast$q$, 2, ARRAY[$q$Simplecast is a podcast hosting and distribution platform that lets creators upload audio, publish an RSS feed, and get their show listed automatically across Apple Podcasts, Spotify, and other major podcast apps.$q$, $q$Founded in 2015 by Brad Smith and based in New York, Simplecast built its reputation on clean publishing tools paired with detailed audience analytics, which set it apart from more bare-bones hosting providers.$q$, $q$In 2020 Simplecast was acquired by SiriusXM and folded into AdsWizz, SiriusXM's advertising technology arm, becoming the company's primary podcast creation and hosting platform while continuing to operate under the Simplecast brand.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Simplecast automates distribution to all major podcast directories through a single RSS feed, and it provides a customizable show website with a custom domain option so podcasters do not need a separate site builder.$q$, $q$Analytics range from basic download counts on the entry-level plan to advanced reporting on higher tiers, including unique listener estimates, geographic breakdowns by country and region, device and app technology data, and side-by-side comparisons across episodes.$q$, $q$For publishers and larger shows, Simplecast supports dynamic ad insertion and campaign management through the AdsWizz Podcast Marketplace, secondary ad-free feeds, third-party attribution partner integrations, and API access for custom workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('be61a68f-a190-43dc-9648-504807d5677a', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The Basic plan costs $15 per month, or $13.50 per month billed annually, and includes two team seats, unlimited storage and uploads, a customizable show website, and 20,000 downloads included per month.$q$, $q$The Essential plan costs $35 per month ($31.50 annually) and adds four team seats along with location analytics, unique listener reporting, web player analytics, and technology analytics, with 50,000 downloads included per month.$q$, $q$Professional and Enterprise plans use custom, quote-based pricing and add monetization through dynamic ad insertion, white-labeled RSS feeds, high-bitrate audio, API integration, and dedicated account support. Every plan includes a 14-day free trial with no credit card required.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Tag-based document organization$q$, $q$Automatically suggests tags and metadata to categorize documents instead of relying on manual folder structures.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Shared and private workspaces$q$, $q$Separates collaborative team document areas from private individual storage within the same system.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Duplicate detection$q$, $q$Identifies duplicate uploads to help keep the document library clean and avoid redundant storage.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Document versioning$q$, $q$Tracks version history so teams can review or revert to earlier versions of a document.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Full-text search$q$, $q$Searches inside document content, not just file names, to help users find what they need quickly.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Cross-platform desktop and mobile apps$q$, $q$Installs as a native-feeling app on Windows, macOS, Linux, Android, and iOS.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Flexible deployment options$q$, $q$Available as cloud SaaS, on-premises self-hosted software, or white-label multi-tenant SaaS.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Nextcloud integration$q$, $q$Sends files directly from Nextcloud Files into SimpleDMS without manual re-uploading.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Automated tag-based sorting reduces manual filing work for small teams$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Flexible deployment as cloud, on-premises, or white-label SaaS suits different compliance needs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Open-source, non-copyleft licensing option appeals to businesses wanting more control$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Cross-platform desktop and mobile apps behave like native software$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Free 30-day trial lowers the barrier to testing the platform$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Limited independently verifiable company information such as founding year or headquarters$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Smaller ecosystem and brand recognition compared to established document management vendors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Entry-level Pro plan storage (5 GB) is modest for document-heavy teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$White-label and on-premises licensing details require direct contact rather than transparent public pricing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Primary market focus on German-speaking Europe may mean less localized support elsewhere$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$What is SimpleDMS used for$q$, $q$SimpleDMS is a document management system that helps small and mid-size businesses store, tag, search, and version their documents without relying on manual folder organization.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Is SimpleDMS open source$q$, $q$Yes, SimpleDMS is offered as open-source software, with a business option to access the source code under a non-copyleft license for on-premises deployment.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$How much does SimpleDMS cost$q$, $q$SimpleDMS pricing starts at roughly CHF 5 per user per month for the Pro plan with 5 GB of storage, with an Unlimited plan at about CHF 395 per month flat for 500 GB and unlimited users.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Can SimpleDMS be self-hosted$q$, $q$Yes, SimpleDMS offers an on-premises deployment option using source code released under a non-copyleft license, in addition to its cloud SaaS offering.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Does SimpleDMS integrate with Nextcloud$q$, $q$Yes, SimpleDMS has a Nextcloud integration that allows files to be sent directly from Nextcloud Files into SimpleDMS.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Is there a free trial for SimpleDMS$q$, $q$Yes, SimpleDMS offers a free 30-day trial before requiring a paid subscription.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$What platforms does SimpleDMS support$q$, $q$SimpleDMS can be installed as a desktop and mobile app on Windows, macOS, Linux, Android, and iOS.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Who is SimpleDMS best suited for$q$, $q$SimpleDMS is best suited for small businesses and freelancers who want automated document organization without the overhead of a large enterprise document management platform.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Automated document filing for small teams$q$, $q$Small businesses use SimpleDMS's tag suggestions to organize incoming documents without maintaining manual folder trees.$q$, $q$Small business owners and freelancers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Self-hosted compliance-sensitive storage$q$, $q$Organizations with data residency requirements deploy SimpleDMS on-premises using the non-copyleft source license.$q$, $q$Compliance-conscious organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$White-label document management for partners$q$, $q$Software resellers and agencies use the white-label SaaS option to offer branded document management to their own clients.$q$, $q$Software resellers and agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Pro$q$, $q$CHF 5/user/month$q$, $q$monthly per user$q$, NULL, $q$["5 GB cloud storage","Unlimited workspaces","Tag-based document organization","Full-text search"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$Unlimited$q$, $q$CHF 395/month$q$, $q$monthly flat rate$q$, NULL, $q$["500 GB cloud storage","Unlimited users and workspaces","Document versioning and duplicate detection","Priority access for growing teams"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$overview$q$, $q$What Is SimpleDMS$q$, 2, ARRAY[$q$SimpleDMS is a document management system aimed at small businesses that want an alternative to manually organized folder structures. Its core idea is that documents should sort themselves, using tags and metadata rather than requiring users to maintain a strict filing hierarchy.$q$, $q$The software is open source and offered through three deployment models: a hosted cloud SaaS product, an on-premises installation using source-available code under a non-copyleft license, and a white-label SaaS option for partners who want to operate their own branded, multi-tenant instance.$q$, $q$SimpleDMS can be installed as a desktop and mobile application on Windows, macOS, Linux, Android, and iOS, where it behaves like a native app after installation and supports operating-system-level integrations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the center of SimpleDMS is a tag-based categorization system paired with metadata suggestions, which helps automate the sorting of incoming documents rather than requiring manual filing into folders.$q$, $q$Workspaces let teams separate shared, collaborative document areas from private individual storage, while duplicate detection and version history help avoid redundant or outdated files.$q$, $q$Full-text search across stored documents and support for multiple document views make it easier to locate files quickly, and integrations such as the Nextcloud connector let teams send files into SimpleDMS directly from existing storage tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$SimpleDMS offers a Pro plan priced at roughly CHF 5 per user per month, which includes 5 GB of cloud storage and unlimited workspaces, aimed at freelancers and small teams.$q$, $q$An Unlimited plan is available at a flat rate of about CHF 395 per month, providing 500 GB of storage with unlimited users and workspaces for larger or growing organizations.$q$, $q$A free 30-day trial is available before committing to a paid plan, and businesses that prefer not to use the hosted cloud option can self-host using the on-premises source code license.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b160eec3-7dec-4749-aa87-4cbf8e786590', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Unlimited email aliases (Premium)$q$, $q$Generates disposable aliases that forward to a real inbox, hiding the user's actual email address from third parties.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Reply from alias$q$, $q$Lets users send replies from an alias address without exposing their real email to the recipient.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Custom domain support$q$, $q$Allows Premium users to create aliases under their own domain rather than only SimpleLogin's shared domains.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Catch-all aliasing$q$, $q$Automatically forwards any email sent to a custom domain, even for aliases not explicitly created in advance.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Browser extensions and mobile apps$q$, $q$Available for Chrome, Firefox, Safari, iOS, and Android for quick alias creation while browsing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$PGP encryption$q$, $q$Premium plan supports PGP encryption for forwarded emails to add an extra layer of message privacy.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Proton Pass integration$q$, $q$Built directly into Proton Pass, letting Proton subscribers generate aliases alongside password management.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Instant alias disable$q$, $q$Aliases can be turned off instantly if they start receiving spam or are exposed in a data breach.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Open-source codebase adds transparency and trust for privacy-focused users$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Backed by Proton AG, a well-established privacy and security company$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Free plan is genuinely usable with 10 aliases and core forwarding features$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Custom domain and catch-all support give power users flexibility beyond basic aliasing$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Tight integration with Proton Pass streamlines alias creation for existing Proton users$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Free plan is capped at only 10 aliases, which power users can exhaust quickly$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$No dedicated family plan for sharing Premium across a household$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Some advanced features require also subscribing to or using Proton Pass$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Pricing has shifted since the Proton Pass integration, which can be confusing for legacy subscribers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Reliant on Proton's broader roadmap now that it is owned by Proton AG rather than fully independent$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Is SimpleLogin free$q$, $q$Yes, SimpleLogin has a free plan with 10 aliases, one mailbox, and reply-from-alias functionality. A Premium plan unlocks unlimited aliases and custom domains.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Who owns SimpleLogin$q$, $q$SimpleLogin was acquired by Proton AG, the company behind ProtonMail and Proton Pass, in April 2022.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$How much does SimpleLogin Premium cost$q$, $q$SimpleLogin Premium costs $4 per month or $36 per year, though pricing following Proton Pass integration is closer to $2.99 per month billed annually at $35.88.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$What is an email alias$q$, $q$An email alias is a disposable, forwarding email address that hides a user's real inbox from websites and services while still delivering messages.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Does SimpleLogin work with Proton Pass$q$, $q$Yes, SimpleLogin is integrated into Proton Pass, allowing Proton subscribers to generate email aliases directly from their password manager.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Is SimpleLogin open source$q$, $q$Yes, SimpleLogin is built on an open-source codebase, which is available for review and self-hosting by technical users.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Can I use my own domain with SimpleLogin$q$, $q$Yes, the Premium plan supports unlimited custom domains and catch-all aliasing under domains the user owns.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$How many users does SimpleLogin have$q$, $q$At the time of its acquisition by Proton in 2022, SimpleLogin had more than 100,000 users who had created over 2 million email aliases.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Reducing spam and data broker exposure$q$, $q$Privacy-conscious individuals use unique aliases for every signup so they can identify and block the source of spam or data leaks.$q$, $q$Privacy-conscious consumers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Protecting a real email during online shopping$q$, $q$Shoppers use disposable aliases for one-off purchases or trials to avoid marketing emails reaching their main inbox.$q$, $q$Online shoppers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Business use of custom domain aliasing$q$, $q$Small teams create department- or purpose-specific aliases under a custom domain for support, sales, or vendor communication.$q$, $q$Small businesses and freelancers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Free$q$, $q$$0$q$, $q$forever$q$, NULL, $q$["10 aliases","1 mailbox","Unlimited bandwidth","Reply from alias","Browser extensions and mobile apps"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$Premium$q$, $q$$4/month or $36/year$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited aliases","Unlimited custom domains","Catch-all domain support","Unlimited mailboxes","PGP encryption"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$overview$q$, $q$What Is SimpleLogin$q$, 2, ARRAY[$q$SimpleLogin is an email alias service that generates disposable, forwarding email addresses so users never have to give their real email address to a website, newsletter, or online account. Messages sent to an alias are forwarded to the user's real inbox, and replies can be sent from the alias without revealing the underlying address.$q$, $q$Founded in 2019, SimpleLogin grew as an open-source alternative to proprietary alias services, offering browser extensions, mobile apps, and a web dashboard for managing aliases.$q$, $q$In April 2022, Proton AG acquired SimpleLogin to strengthen its privacy product suite. SimpleLogin continues to operate as its own service while also powering alias creation inside Proton Pass, Proton's password manager.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Users can create unlimited email aliases on the Premium plan (10 on the free plan), each of which forwards to a designated mailbox and can be disabled instantly if it starts receiving spam or is linked to a data breach.$q$, $q$SimpleLogin supports custom domains and catch-all aliasing, so users or businesses can generate on-the-fly aliases under their own domain rather than relying only on SimpleLogin's shared domains.$q$, $q$The service integrates with Proton Pass, giving Proton subscribers built-in alias generation alongside password management, plus PGP encryption support and browser extensions for major browsers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The Free plan includes 10 aliases, one mailbox, unlimited bandwidth, reply-from-alias capability, and access to browser extensions and mobile apps.$q$, $q$The Premium plan is priced at $4 per month or $36 per year, and following integration with Proton Pass, new subscribers are billed around $2.99 per month ($35.88 per year), which also includes Proton Pass Plus features like unlimited vaults and a built-in two-factor authenticator.$q$, $q$Premium unlocks unlimited aliases, unlimited custom domains, catch-all domain support, multiple mailboxes, and PGP encryption, with payment accepted via card, PayPal, Apple Pay, and select cryptocurrencies.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e645d12e-427d-4de8-a46d-9232f2a915d2', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Online scheduling and reminders$q$, $q$Lets clients book appointments online and sends automated email and text reminders to reduce no-shows.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$HIPAA-compliant telehealth$q$, $q$Built-in video sessions allow clinicians to see clients remotely without a separate video conferencing tool.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Customizable documentation$q$, $q$Intake forms, progress notes, and treatment plans can be tailored to a clinician's specialty and workflow.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Insurance billing and claims$q$, $q$Supports electronic claim submission, superbills, and payment processing for practices that accept insurance.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Secure client portal$q$, $q$Gives clients a place to complete paperwork, message their provider, and view upcoming appointments.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Group practice management$q$, $q$Plus plan supports multiple clinicians under one practice account with role-based access.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Practice analytics and reporting$q$, $q$Provides reporting on appointments, billing, and practice performance for owners managing a growing caseload.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Purpose-built specifically for therapists and health and wellness professionals$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Combines scheduling, telehealth, documentation, and billing in one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Large, established user base of over 225,000 practitioners$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$HIPAA-compliant telehealth is built in rather than requiring a separate tool$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Free trial with a discount available for early sign-up on a paid plan$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Pricing rises meaningfully for group practices with per-clinician fees on top of the base plan$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Some advanced billing and insurance features are limited to higher-tier plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Ownership changes (EngageSmart, then Vista Equity Partners) may raise questions for long-term customers about product direction$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Learning curve for clinicians unfamiliar with EHR software$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Primarily built around US insurance and compliance workflows, limiting fit for practices outside the United States$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$How much does SimplePractice cost$q$, $q$SimplePractice's Starter plan begins at $49 per month, with a Plus plan for group practices starting at $99 per month plus roughly $59 per month per additional clinician.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Who founded SimplePractice$q$, $q$SimplePractice was founded in 2012 by Howard Spector in Santa Monica, California, while he was training to become a Marriage and Family Therapist.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Is SimplePractice HIPAA compliant$q$, $q$Yes, SimplePractice includes HIPAA-compliant telehealth video sessions and secure documentation designed for health and wellness practices.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Who owns SimplePractice now$q$, $q$SimplePractice was acquired by EngageSmart in 2021, and in January 2024 EngageSmart was taken private by Vista Equity Partners in a deal valued at roughly four billion dollars.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Does SimplePractice support insurance billing$q$, $q$Yes, SimplePractice supports electronic insurance claim submission, superbill generation, and payment processing for practices that accept insurance.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Is there a free trial for SimplePractice$q$, $q$Yes, SimplePractice offers a free trial, and customers who start a paid plan within the first seven days can receive a discount on their first three months.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Who uses SimplePractice$q$, $q$SimplePractice is used by therapists, counselors, psychologists, and other health and wellness professionals running solo or group private practices, with more than 225,000 practitioners on the platform.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Does SimplePractice support group practices$q$, $q$Yes, the Plus plan is designed for group practices and supports multiple clinicians under one account with role-based access.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Solo therapy practice management$q$, $q$Individual therapists use SimplePractice's Starter plan to manage scheduling, notes, and billing without extra administrative staff.$q$, $q$Solo therapists and counselors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Group behavioral health practices$q$, $q$Multi-clinician practices use the Plus plan to centralize scheduling, billing, and documentation across an entire team.$q$, $q$Group practice owners and administrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Telehealth-first care delivery$q$, $q$Clinicians offering remote sessions use SimplePractice's built-in HIPAA-compliant video instead of a separate telehealth tool.$q$, $q$Telehealth providers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Starter$q$, $q$$49/month$q$, $q$monthly$q$, NULL, $q$["Online scheduling and reminders","Client portal","Customizable documentation","Basic billing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Essential$q$, $q$Contact for pricing$q$, $q$monthly$q$, NULL, $q$["Everything in Starter","Advanced billing tools","Telehealth video sessions","Expanded reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$Plus$q$, $q$$99/month base plus approx $59/month per additional clinician$q$, $q$monthly$q$, NULL, $q$["Group practice management","Role-based team access","Insurance claim submission","Shared client scheduling across clinicians"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$overview$q$, $q$What Is SimplePractice$q$, 2, ARRAY[$q$SimplePractice is a practice management and EHR platform purpose-built for health and wellness professionals running their own practice, most commonly therapists, counselors, psychologists, and similar clinicians in private or group practice settings.$q$, $q$The company was founded in 2012 by Howard Spector in Santa Monica, California, where it remains headquartered. It grew from a solo project into a platform used by more than 225,000 practitioners across the United States.$q$, $q$SimplePractice has changed ownership over time: it was acquired by EngageSmart in 2021, and in January 2024 EngageSmart, along with SimplePractice, was taken private in a roughly four billion dollar acquisition by Vista Equity Partners, while continuing to operate under its own brand.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform covers the core administrative workflow of a health and wellness practice: online appointment scheduling, automated reminders, a secure client portal, and customizable intake forms and progress notes tailored for clinical documentation.$q$, $q$SimplePractice includes HIPAA-compliant telehealth video sessions built directly into the platform, so clinicians can see clients remotely without a separate video tool, along with e-prescribing and treatment planning features on relevant plans.$q$, $q$Billing tools support credit card processing, superbill generation, and electronic insurance claim submission, which is a major differentiator for solo and group practices that accept insurance.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c1f93663-fc76-4430-8326-61a4f8cb731a', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$SimplePractice's Starter plan begins at $49 per month, targeting solo practitioners who need core scheduling, documentation, and billing features.$q$, $q$Higher tiers add features like advanced insurance billing and more robust reporting, with the Plus plan for group practices starting at $99 per month as a base fee, plus roughly $59 per month for each additional clinician added to the account.$q$, $q$New users can begin a paid subscription within the first seven days of the free trial to receive a discount, commonly around 50 percent off, for their first three months.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$AI copywriting$q$, $q$Generates marketing copy for blog posts, ads, product descriptions, and social captions using AI credits.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Drag-and-drop design editor$q$, $q$Provides templates, over 1,000 fonts, and stock assets for creating graphics without design experience.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$AI video generation and editing$q$, $q$Supports video creation and editing tools alongside AI-assisted video generation features.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Social media scheduling$q$, $q$Lets marketing teams plan and publish content across multiple social channels from one dashboard.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Brand kits$q$, $q$Stores brand colors, fonts, and logos so design and content stay consistent across a team.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Team collaboration$q$, $q$Allows multiple users to collaborate on design and content projects within shared workspaces.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Credit-based AI usage$q$, $q$Uses a credit system for AI-generated content and assets that scales with the subscription tier.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Combines design, AI writing, video, and scheduling in one subscription instead of several separate tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Free Forever plan offers real usable value including unlimited design projects$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Backed by notable investors including Craft Ventures and Khosla Ventures$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$AI features reduce the time needed to produce first-draft marketing content$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Actively positioned and marketed as a lower-cost alternative to stacking Canva plus a writing tool plus a scheduler$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Credit-based AI pricing can be confusing and may run out faster than expected for heavy users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Design depth is generally considered less mature than dedicated tools like Canva or Adobe Express$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Free plan's AI credits are a one-time allotment rather than a recurring monthly amount$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Company size and precise headcount are not consistently reported across sources$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$As a newer, VC-funded company, pricing and feature sets have changed over time$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Is Simplified free to use$q$, $q$Yes, Simplified offers a Free Forever plan with unlimited design projects, over 1,000 fonts, and 500 MB of storage, plus a one-time AI credit allotment.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$How much does Simplified cost$q$, $q$Paid plans include Pro at $29 per month, Business at $79 per month, and Growth at $199 per month, with custom Enterprise pricing for larger teams.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Who founded Simplified$q$, $q$Simplified was founded in 2020 by CEO KD Deshpande and operates under the legal entity TLDR Technologies, Inc., headquartered in San Francisco.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Is Simplified a Canva alternative$q$, $q$Yes, Simplified is commonly positioned as an alternative to Canva, adding AI copywriting, video tools, and social scheduling alongside graphic design.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Does Simplified include AI copywriting$q$, $q$Yes, Simplified includes AI copywriting tools for blog posts, ads, product descriptions, and social captions using a credit-based system.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Can I schedule social media posts in Simplified$q$, $q$Yes, Simplified includes a built-in social media scheduler for planning and publishing content across multiple channels.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Has Simplified raised funding$q$, $q$Yes, Simplified raised a pre-seed round of about $2.2 million and an $8.5 million seed round led by Craft Ventures, with participation from Khosla Ventures and other investors.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Who is Simplified designed for$q$, $q$Simplified is designed for small businesses, freelancers, and in-house marketing teams that want to consolidate design, writing, video, and scheduling tools into one platform.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Small business marketing content$q$, $q$Small business owners use Simplified to produce social graphics, ad copy, and short videos without hiring a designer or copywriter.$q$, $q$Small business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$In-house marketing team workflows$q$, $q$Marketing teams consolidate design, copywriting, video, and scheduling into one platform to reduce tool sprawl.$q$, $q$In-house marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Freelance content creation$q$, $q$Freelancers use Simplified's AI writing and design tools to deliver client content faster across multiple formats.$q$, $q$Freelance marketers and designers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Free Forever$q$, $q$$0$q$, $q$forever$q$, NULL, $q$["Unlimited design projects","1,000+ fonts","500 MB storage","One-time AI credit allotment"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Pro$q$, $q$$29/month$q$, $q$monthly$q$, NULL, $q$["Increased monthly AI credits","Expanded storage","Additional brand kits","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Business$q$, $q$$79/month$q$, $q$monthly$q$, NULL, $q$["Higher AI credit allowance","More collaboration seats","Advanced brand controls","Extended storage"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Growth$q$, $q$$199/month$q$, $q$monthly$q$, NULL, $q$["Largest self-serve AI credit allowance","Maximum storage and seats","Advanced team workflows","Dedicated support options"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Enterprise$q$, $q$Custom$q$, $q$contact sales$q$, NULL, $q$["Custom AI credit volume","Dedicated account management","Advanced security and admin controls","Custom onboarding"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$overview$q$, $q$What Is Simplified$q$, 2, ARRAY[$q$Simplified is an all-in-one AI content creation platform that bundles graphic design, AI copywriting, video editing, and social media scheduling into a single subscription, aimed at marketing teams and small businesses that want to avoid juggling multiple point solutions.$q$, $q$The company was founded in 2020 by KD Deshpande and operates under the legal name TLDR Technologies, Inc., headquartered in San Francisco, California. It has raised early-stage venture funding including a seed round led by Craft Ventures.$q$, $q$Simplified is often positioned as a challenger to Canva, but it differentiates itself by weaving AI writing and video tools directly into the design workflow, rather than focusing on design alone.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The design editor supports drag-and-drop graphic creation with access to over 1,000 fonts, templates, and stock assets, aimed at users without formal design training.$q$, $q$AI copywriting tools generate marketing copy such as blog posts, ad text, product descriptions, and social captions, using credit-based usage that scales with the subscription tier.$q$, $q$Video tools include editing and AI-assisted video generation, while a built-in social media scheduler lets teams plan and publish content across multiple channels from within the same platform.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Simplified's Free Forever plan includes unlimited design projects, over 1,000 fonts, 500 MB of storage, and a one-time AI credit allotment that does not renew monthly.$q$, $q$The Pro plan is priced at $29 per month, the Business plan at $79 per month, and the Growth plan at $199 per month, with each tier increasing monthly AI credits, storage, and collaboration features.$q$, $q$A custom-priced Enterprise plan is available for larger organizations that need additional seats, brand controls, and dedicated support.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Customizable booking page$q$, $q$Lets clients book services, choose staff, and select appointment times through a branded, embeddable booking page.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Automated reminders$q$, $q$Sends automatic email and text reminders to reduce no-shows and last-minute cancellations.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Client management$q$, $q$Tracks client booking history, notes, and contact details in a central database.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Payment processing$q$, $q$Accepts online payments and deposits at the time of booking through integrated payment providers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Marketing tools$q$, $q$Includes promotions, coupons, gift cards, and loyalty points to encourage repeat bookings.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Add-on marketplace$q$, $q$Offers optional add-ons such as memberships, group classes, intake forms, and video conferencing.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Multi-language booking pages$q$, $q$Supports multiple languages on the booking interface and through multilingual customer support.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Multi-location and enterprise support$q$, $q$Enterprise plan supports franchises and multi-location businesses with centralized management.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Generous free plan makes it accessible for solo professionals starting out$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Wide range of add-ons lets businesses customize functionality without switching platforms$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Multilingual booking pages and support suit businesses with international clients$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Marketing tools like gift cards and loyalty points go beyond basic scheduling$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Scales from solo professionals up to multi-location enterprise businesses$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Interface can feel dated compared to newer scheduling tools like Calendly$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Many advanced features are gated behind paid add-ons, which can increase total cost$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Enterprise pricing is not publicly listed and requires contacting sales$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Learning curve exists for businesses that want to configure the full add-on ecosystem$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Exact founding year is reported inconsistently across sources (2009 launch versus 2011 rebrand)$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Is SimplyBook.me free$q$, $q$Yes, SimplyBook.me offers a Free plan for solo professionals with a limited number of monthly bookings, along with paid plans for larger teams.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$How much does SimplyBook.me cost$q$, $q$Paid plans range from roughly $8.25 to $13.90 per month for small teams up to $59.90 per month for the Premium plan, with custom Enterprise pricing for larger organizations.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Where is SimplyBook.me based$q$, $q$SimplyBook.me is headquartered in Cyprus and operates offices in multiple countries, with roots in a booking system originally developed in Iceland.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Who owns SimplyBook.me$q$, $q$SimplyBook.me was acquired by team.blue, a European hosting and software group, in September 2023.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Does SimplyBook.me support multiple languages$q$, $q$Yes, SimplyBook.me supports multiple languages on its booking pages and offers multilingual customer support covering English, Spanish, French, Portuguese, Chinese, and Ukrainian.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$What types of businesses use SimplyBook.me$q$, $q$SimplyBook.me is used by salons, healthcare providers, consultants, tutors, fitness studios, and other service-based businesses that take appointments.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Does SimplyBook.me support payments$q$, $q$Yes, SimplyBook.me integrates with payment providers to accept online payments and deposits at the time of booking.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Can SimplyBook.me support multiple business locations$q$, $q$Yes, the Enterprise plan is designed for multi-location chains, franchises, and organizations with centralized booking management needs.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Solo service professional scheduling$q$, $q$Independent consultants, tutors, or therapists use the Free or Basic plan to accept online bookings without hiring administrative staff.$q$, $q$Solo service professionals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Salon and wellness studio management$q$, $q$Salons and studios use staff-based booking, payment processing, and marketing add-ons to manage a growing client base.$q$, $q$Salons and wellness studios$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Multi-location and franchise booking$q$, $q$Healthcare networks, universities, and franchise businesses use the Enterprise plan to centralize booking across many locations.$q$, $q$Multi-location enterprises and franchises$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["Limited monthly bookings","1 staff provider","Basic booking page","Client management"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Basic$q$, $q$From $8.25/month$q$, $q$monthly$q$, NULL, $q$["More monthly bookings","Automated reminders","Basic customization","Email support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Standard$q$, $q$Up to $13.90/month$q$, $q$monthly$q$, NULL, $q$["Increased booking volume","Multiple staff providers","Payment processing","Marketing add-ons available"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Premium$q$, $q$Up to $59.90/month$q$, $q$monthly$q$, NULL, $q$["5 to 30 staff providers","Advanced marketing tools","Higher booking volume","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$Enterprise$q$, $q$Custom$q$, $q$contact sales$q$, NULL, $q$["Multi-location management","Custom data residency requirements","Dedicated integrations","Franchise and chain support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$overview$q$, $q$What Is SimplyBook.me$q$, 2, ARRAY[$q$SimplyBook.me is an online appointment booking system that helps service-based businesses accept bookings, manage clients, and take payments through a customizable booking page and dashboard.$q$, $q$The product originated with Notando Ltd. in Iceland and was launched as a SaaS booking platform in 2009, later adopting the SimplyBook.me brand around 2011. The company is now headquartered in Cyprus with offices in multiple countries.$q$, $q$In September 2023, SimplyBook.me was acquired by team.blue, a European hosting and software group, while continuing to operate under its own brand and product.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Businesses can build a customizable, branded booking page where clients choose services, staff, and appointment times, with automated confirmation and reminder emails or texts to reduce no-shows.$q$, $q$The platform includes client management with booking history and notes, payment processing, and marketing tools such as promotions, coupons, gift cards, and a loyalty points system to help businesses drive repeat bookings.$q$, $q$SimplyBook.me offers an extensive add-on marketplace, letting businesses turn on features like memberships, classes, intake forms, or video conferencing only when needed, which keeps the base product lean while still supporting complex use cases.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('46f3d2a9-02b8-43f2-a139-956dd022d4b6', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$SimplyBook.me offers a Free plan for solo professionals with a limited number of bookings per month, alongside Basic and Standard plans priced roughly between $8.25 and $13.90 per month for small teams.$q$, $q$The Premium plan costs up to $59.90 per month and is aimed at growing service businesses with five to thirty staff providers who need more advanced features and higher booking volume.$q$, $q$An Enterprise plan is available with custom, per-customer pricing for multi-location chains, franchises, healthcare networks, universities, and corporate clients with specific data residency or integration needs.$q$]::text[], 2);
